-- Convert the 12 "Intensive Listening Intermediate N" lessons (N = 2..13) in
-- "The Canto to Mando Blueprint - Intermediate" from Audio to Listening
-- Practice, keeping their titles and loading the Mandarin sentences from the
-- Intensive Listening doc. Pinyin = the doc's (typos corrected, cleaned to one
-- syllable per character); English = translations; audio = per-sentence TTS
-- (audioUrl null). Lesson 1 is intentionally not included (already done).
--
-- Idempotent + tightly scoped: only lessons still typed 'audio', titled
-- "Intensive Listening…", in that course, matched to their content by the
-- number in the title. Re-running is a no-op.

UPDATE "course_library_lessons" AS l
SET "lesson_type" = 'listening_practice',
    "content" = v.content,
    "updated_at" = now()
FROM (VALUES
  (2, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"efc1491d-3580-47c5-856d-72189af9233e","order":0,"chinese":"你走得这么快!","pinyin":"nǐ zǒu de zhè me kuài","english":"You walk so fast!","audioUrl":null},{"id":"44c8c130-c381-448a-8866-6af2e98a842b","order":1,"chinese":"你们吃得那么慢","pinyin":"nǐ men chī de nà me màn","english":"You guys eat so slowly","audioUrl":null},{"id":"7f36fb30-c35d-434e-85f4-182c899282ad","order":2,"chinese":"我在飞机上睡得这么差","pinyin":"wǒ zài fēi jī shàng shuì de zhè me chà","english":"I slept so badly on the plane","audioUrl":null},{"id":"a33047ab-62de-4d4c-8cbf-fdee39fdbeea","order":3,"chinese":"我不知道海里面会有那么多鱼","pinyin":"wǒ bù zhī dào hǎi lǐ miàn huì yǒu nà me duō yú","english":"I didn''t know there would be so many fish in the sea","audioUrl":null},{"id":"d4171302-5e45-4dc6-9327-e770637cf3bd","order":4,"chinese":"如果你继续这样追她, 她会不喜欢你","pinyin":"rú guǒ nǐ jì xù zhè yàng zhuī tā tā huì bù xǐ huan nǐ","english":"If you keep chasing her like this, she won''t like you","audioUrl":null},{"id":"f6c79c26-5c10-4fb6-92cd-7119fd1752d2","order":5,"chinese":"你要继续这样做","pinyin":"nǐ yào jì xù zhè yàng zuò","english":"You have to keep doing it like this","audioUrl":null},{"id":"b000f2a0-1c18-4887-8345-4156559dd2af","order":6,"chinese":"你觉得这样做很好吗？","pinyin":"nǐ jué de zhè yàng zuò hěn hǎo ma","english":"Do you think doing it this way is good?","audioUrl":null},{"id":"d8c96c2a-44e0-46ec-a661-e470548ecef1","order":7,"chinese":"就算是这样, 我会继续喜欢她","pinyin":"jiù suàn shì zhè yàng wǒ huì jì xù xǐ huan tā","english":"Even so, I''ll keep liking her","audioUrl":null},{"id":"3b147f5f-f9b0-459d-92c7-d7236e3a2b24","order":8,"chinese":"那你今晚想做什么?","pinyin":"nà nǐ jīn wǎn xiǎng zuò shén me","english":"So what do you want to do tonight?","audioUrl":null},{"id":"6f7cb337-c257-47e7-83cc-4f57993371de","order":9,"chinese":"那如果你喜欢她, 你要去追她","pinyin":"nà rú guǒ nǐ xǐ huan tā nǐ yào qù zhuī tā","english":"Well, if you like her, you should go after her","audioUrl":null},{"id":"328756c1-f97b-4386-bd26-9c4da3bda668","order":10,"chinese":"那我们要去追那个明星","pinyin":"nà wǒ men yào qù zhuī nà ge míng xīng","english":"Then we should go chase that celebrity","audioUrl":null},{"id":"5e0cc2de-5828-4d71-a39d-4a70327c4c92","order":11,"chinese":"那你跑步要跑得快一点","pinyin":"nà nǐ pǎo bù yào pǎo de kuài yì diǎn","english":"Then you need to run a bit faster","audioUrl":null},{"id":"378e4e4a-e7d1-4403-9093-c549a83839b9","order":12,"chinese":"我可以说一点中文","pinyin":"wǒ kě yǐ shuō yì diǎn zhōng wén","english":"I can speak a little Chinese","audioUrl":null},{"id":"70bc2d64-820f-4b23-8a2e-5bc48f8c3fcd","order":13,"chinese":"给我多点水","pinyin":"gěi wǒ duō diǎn shuǐ","english":"Give me more water","audioUrl":null},{"id":"47e44706-c214-4106-a638-5a83016ea8be","order":14,"chinese":"可以多加一点吗","pinyin":"kě yǐ duō jiā yì diǎn ma","english":"Can you add a little more?","audioUrl":null},{"id":"6af14583-8661-4e1d-a3d1-8d3895c1792d","order":15,"chinese":"那你这样说是对的","pinyin":"nà nǐ zhè yàng shuō shì duì de","english":"Then what you''re saying is right","audioUrl":null},{"id":"8caece5c-bbf4-4f94-9d89-181438f1ba62","order":16,"chinese":"那么高! 请介绍一下你的朋友!","pinyin":"nà me gāo qǐng jiè shào yí xià nǐ de péng you","english":"So tall! Please introduce your friend!","audioUrl":null},{"id":"2ff52803-cbdc-4a0c-a27b-3ff83175fc35","order":17,"chinese":"要做那么多功课? 我哪里有时间","pinyin":"yào zuò nà me duō gōng kè wǒ nǎ lǐ yǒu shí jiān","english":"So much homework to do? Where would I find the time?","audioUrl":null}]}'::jsonb),
  (3, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"6e418ba0-1e8d-428d-b155-2a1e16f2affd","order":0,"chinese":"千万不要坐在中间位置","pinyin":"qiān wàn bú yào zuò zài zhōng jiān wèi zhi","english":"Whatever you do, don''t sit in the middle seat","audioUrl":null},{"id":"3072bd9f-4e59-403f-aac1-3ec792b2be71","order":1,"chinese":"注意安全！千万别解开你的安全带","pinyin":"zhù yì ān quán qiān wàn bié jiě kāi nǐ de ān quán dài","english":"Stay safe! Whatever you do, don''t unfasten your seatbelt","audioUrl":null},{"id":"2a504499-528a-41ca-822b-ccd5d02620e8","order":2,"chinese":"千万不要和不愿意公开关系的男人谈恋爱","pinyin":"qiān wàn bú yào hé bú yuàn yì gōng kāi guān xi de nán rén tán liàn ài","english":"Never date a man who isn''t willing to make the relationship public","audioUrl":null},{"id":"dd44002d-dcda-4adf-86c9-18b4aff0f6ac","order":3,"chinese":"不用袋子了! 谢谢!","pinyin":"bú yòng dài zi le xiè xiè","english":"No bag needed! Thanks!","audioUrl":null},{"id":"a0d7e368-d504-493c-a16b-774671329f59","order":4,"chinese":"老师说明天不用上学","pinyin":"lǎo shī shuō míng tiān bú yòng shàng xué","english":"The teacher said we don''t have to go to school tomorrow","audioUrl":null},{"id":"463bd469-06f8-4421-ba0b-112b2f63e853","order":5,"chinese":"进来的时候不用脱鞋子","pinyin":"jìn lái de shí hòu bú yòng tuō xié zi","english":"You don''t need to take off your shoes when you come in","audioUrl":null},{"id":"93bff0ed-a48e-4d6e-b072-01ef42102179","order":6,"chinese":"你为什么要在我面前脱衣服","pinyin":"nǐ wèi shén me yào zài wǒ miàn qián tuō yī fu","english":"Why are you taking off your clothes in front of me?","audioUrl":null},{"id":"605a2c8f-4db4-4cf4-b780-4061313c90e8","order":7,"chinese":"你进来就要脱鞋子","pinyin":"nǐ jìn lái jiù yào tuō xié zi","english":"You have to take off your shoes when you come in","audioUrl":null},{"id":"d123ed89-0eb5-475a-98d9-dd20c4fb6e84","order":8,"chinese":"女人说 “不用麻烦你” 是什么意思","pinyin":"nǚ rén shuō bú yòng má fan nǐ shì shén me yì si","english":"What does it mean when a woman says “don''t trouble yourself”?","audioUrl":null},{"id":"f47462f7-254b-4dcd-8aca-11c24dcd6e7c","order":9,"chinese":"请大家不要在这里抽烟","pinyin":"qǐng dà jiā bú yào zài zhè lǐ chōu yān","english":"Everyone, please don''t smoke here","audioUrl":null},{"id":"90301283-30ff-46f4-b803-3797f7fab962","order":10,"chinese":"别这样想","pinyin":"bié zhè yàng xiǎng","english":"Don''t think like that","audioUrl":null}]}'::jsonb),
  (4, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"d35e130f-d5e2-4c48-867d-5cf7c8f4582c","order":0,"chinese":"我今年已经花了很多钱","pinyin":"wǒ jīn nián yǐ jīng huā le hěn duō qián","english":"I''ve already spent a lot of money this year","audioUrl":null},{"id":"8e79dffb-f54c-4107-9faf-b0c2490623a3","order":1,"chinese":"全世界会来这个广场花钱","pinyin":"quán shì jiè huì lái zhè ge guǎng chǎng huā qián","english":"People from all over the world come to this square to spend money","audioUrl":null},{"id":"87a471b3-31d5-4959-bcd8-f3e5da6e2cd4","order":2,"chinese":"我已经发了那个电子邮件给你了","pinyin":"wǒ yǐ jīng fā le nà ge diàn zǐ yóu jiàn gěi nǐ le","english":"I''ve already sent you that email","audioUrl":null},{"id":"ca913279-b8d1-4f81-9484-bc35d136dc00","order":3,"chinese":"他已经到了能够决定的年纪了","pinyin":"tā yǐ jīng dào le néng gòu jué dìng de nián jì le","english":"He''s already old enough to make his own decisions","audioUrl":null},{"id":"1c901a4e-b9d1-4b1b-b129-c43d0a542b01","order":4,"chinese":"好奇怪... 每一扇门都开不了","pinyin":"hǎo qí guài měi yí shàn mén dōu kāi bù liǎo","english":"How strange... none of the doors will open","audioUrl":null},{"id":"4d40783a-70f5-40bc-b7c8-33ea70a2bbb4","order":5,"chinese":"我开不了枪, 你没有装子弹","pinyin":"wǒ kāi bù liǎo qiāng nǐ méi yǒu zhuāng zǐ dàn","english":"I can''t fire the gun, you didn''t load the bullets","audioUrl":null},{"id":"d6985a76-441d-4c68-a945-2633aea555d8","order":6,"chinese":"第一个原因是因为你肯定做不了","pinyin":"dì yī gè yuán yīn shì yīn wèi nǐ kěn dìng zuò bù liǎo","english":"The first reason is that you definitely won''t be able to do it","audioUrl":null},{"id":"6db04179-0ae4-4a82-9e12-40b6b1f33a04","order":7,"chinese":"谢谢你的热情服务! 但是我吃不了了!","pinyin":"xiè xiè nǐ de rè qíng fú wù dàn shì wǒ chī bù liǎo le","english":"Thank you for the warm service! But I can''t eat any more!","audioUrl":null},{"id":"ee236c3f-219f-4a57-8828-ac23625bda0c","order":8,"chinese":"之后的事我就控制不了了!","pinyin":"zhī hòu de shì wǒ jiù kòng zhì bù liǎo le","english":"After that, it''ll be out of my control!","audioUrl":null},{"id":"adb46315-dc25-40aa-8d2f-81f4400986ac","order":9,"chinese":"而且, 我们现在改不了了","pinyin":"ér qiě wǒ men xiàn zài gǎi bù liǎo le","english":"Besides, we can''t change it now","audioUrl":null},{"id":"73b9d825-00c5-445f-9ce9-d0297f3f3c87","order":10,"chinese":"但是下次你别再试了","pinyin":"dàn shì xià cì nǐ bié zài shì le","english":"But don''t try again next time","audioUrl":null},{"id":"e6600671-655c-49c4-bd7a-604935f5a363","order":11,"chinese":"不要再问关于他的问题了","pinyin":"bú yào zài wèn guān yú tā de wèn tí le","english":"Don''t ask any more questions about him","audioUrl":null},{"id":"732c4647-ff96-4ff2-aa7b-3a3c737cf8ca","order":12,"chinese":"我的雨伞关不了了","pinyin":"wǒ de yǔ sǎn guān bù liǎo le","english":"My umbrella won''t close anymore","audioUrl":null}]}'::jsonb),
  (5, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"3629d75f-7b49-4d71-8668-4d5fe003bb68","order":0,"chinese":"他们说我们爱男人只为了 钱","pinyin":"tā men shuō wǒ men ài nán rén zhǐ wèi le qián","english":"They say we only love men for money","audioUrl":null},{"id":"3f4998cc-7ab4-4e78-93a1-4b881ebe8fcd","order":1,"chinese":"为了赚钱, 你就离开了我","pinyin":"wèi le zhuàn qián nǐ jiù lí kāi le wǒ","english":"You left me just to make money","audioUrl":null},{"id":"95789176-1b89-4a4d-b569-a3cb2bd8d3b5","order":2,"chinese":"你天天去见他, 是为了什么","pinyin":"nǐ tiān tiān qù jiàn tā shì wèi le shén me","english":"You go see him every day — what for?","audioUrl":null},{"id":"b251392a-c1d5-4f58-8391-f538b9d252c6","order":3,"chinese":"原因是为了给你我的旧照相机","pinyin":"yuán yīn shì wèi le gěi nǐ wǒ de jiù zhào xiàng jī","english":"The reason is to give you my old camera","audioUrl":null},{"id":"22cea54c-0898-457e-abcb-deca0c281c04","order":4,"chinese":"为了帮他拍照, 我经常要去街道","pinyin":"wèi le bāng tā pāi zhào wǒ jīng cháng yào qù jiē dào","english":"To take photos for him, I often have to go out to the streets","audioUrl":null},{"id":"80d2f291-c007-46d5-b3fb-c109ed146904","order":5,"chinese":"只有你还没吃完饭","pinyin":"zhǐ yǒu nǐ hái méi chī wán fàn","english":"You''re the only one who hasn''t finished eating","audioUrl":null},{"id":"fc3487fa-5945-410b-b688-9e03b20c65af","order":6,"chinese":"只有这袋米有那个奇怪的味道","pinyin":"zhǐ yǒu zhè dài mǐ yǒu nà ge qí guài de wèi dao","english":"Only this bag of rice has that strange smell","audioUrl":null},{"id":"1c7cb480-b46f-47f3-b998-9c2b90da5af3","order":7,"chinese":"今天好像只有那间餐厅开门","pinyin":"jīn tiān hǎo xiàng zhǐ yǒu nà jiān cān tīng kāi mén","english":"It seems only that restaurant is open today","audioUrl":null},{"id":"ebbf55e1-fe5c-4b26-99dd-5f6fa625be05","order":8,"chinese":"现在北京的天气好像很热","pinyin":"xiàn zài běi jīng de tiān qì hǎo xiàng hěn rè","english":"The weather in Beijing seems really hot right now","audioUrl":null},{"id":"07a02ae3-e6a5-4c4a-9b5d-956acb66002d","order":9,"chinese":"原来机票的价钱是一千块钱","pinyin":"yuán lái jī piào de jià qian shì yì qiān kuài qián","english":"It turns out the plane ticket costs a thousand dollars","audioUrl":null},{"id":"9deae79e-8034-48b1-9d7a-008dd522dc5a","order":10,"chinese":"我家附近的超市很贵! 要带几百块钱!","pinyin":"wǒ jiā fù jìn de chāo shì hěn guì yào dài jǐ bǎi kuài qián","english":"The supermarket near my home is expensive — you need to bring a few hundred dollars!","audioUrl":null},{"id":"27365394-4fc6-4a62-aa79-f0b6bb435812","order":11,"chinese":"小姐, 好像只有你还没选好","pinyin":"xiǎo jie hǎo xiàng zhǐ yǒu nǐ hái méi xuǎn hǎo","english":"Miss, it seems you''re the only one who hasn''t decided yet","audioUrl":null}]}'::jsonb),
  (6, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"6eb2ebe8-e208-4575-95dc-64c43d9e2de1","order":0,"chinese":"我妈妈也不是很开心","pinyin":"wǒ mā ma yě bú shì hěn kāi xīn","english":"My mom isn''t very happy either","audioUrl":null},{"id":"e10b9841-8a49-47a9-8a66-562a7d603e83","order":1,"chinese":"你也没有兴趣上班吗","pinyin":"nǐ yě méi yǒu xìng qù shàng bān ma","english":"Are you also not interested in going to work?","audioUrl":null},{"id":"fa909faf-2032-46c2-8522-0bd5cfec5f36","order":2,"chinese":"你们也觉得我的男朋友很无聊吗","pinyin":"nǐ men yě jué de wǒ de nán péng you hěn wú liáo ma","english":"Do you guys also think my boyfriend is boring?","audioUrl":null},{"id":"f2251370-08ba-4dab-9505-df39549d899b","order":3,"chinese":"我觉得和他出去很无聊","pinyin":"wǒ jué de hé tā chū qù hěn wú liáo","english":"I think going out with him is boring","audioUrl":null},{"id":"a33ffecd-7277-4c41-8c2a-a7233034709c","order":4,"chinese":"我觉得上学很无聊","pinyin":"wǒ jué de shàng xué hěn wú liáo","english":"I think going to school is boring","audioUrl":null},{"id":"a8b10560-a5b6-4fa2-9af6-590df262cc6a","order":5,"chinese":"我什么都想要","pinyin":"wǒ shén me dōu xiǎng yào","english":"I want everything","audioUrl":null},{"id":"8293ef1a-cd58-4581-b1ae-3b0aae6562ee","order":6,"chinese":"我觉得全部问题都很难","pinyin":"wǒ jué de quán bù wèn tí dōu hěn nán","english":"I think all the questions are hard","audioUrl":null},{"id":"093dff81-5638-4dd6-9492-8a0df68f077d","order":7,"chinese":"你所有答案都对","pinyin":"nǐ suǒ yǒu dá àn dōu duì","english":"All your answers are correct","audioUrl":null},{"id":"4843f5ba-dfde-4c20-b775-315130aab739","order":8,"chinese":"我觉得今天考试所有问题都很容易","pinyin":"wǒ jué de jīn tiān kǎo shì suǒ yǒu wèn tí dōu hěn róng yì","english":"I think all the questions on today''s exam were easy","audioUrl":null},{"id":"72af0678-0dab-4b21-ada8-d61c049b0f67","order":9,"chinese":"任何人都会这样想","pinyin":"rèn hé rén dōu huì zhè yàng xiǎng","english":"Anyone would think this way","audioUrl":null},{"id":"dcaa6dbc-1a2c-409e-96e1-f6f15e5120d4","order":10,"chinese":"你选任何颜色都可以","pinyin":"nǐ xuǎn rèn hé yán sè dōu kě jǐ","english":"You can pick any color you like","audioUrl":null},{"id":"96d4e071-301c-4436-9198-1da4adf53dcd","order":11,"chinese":"我也觉得上学很容易很无聊","pinyin":"wǒ yě jué de shàng xué hěn róng yì hěn wú liáo","english":"I also think school is easy and boring","audioUrl":null},{"id":"6ce01895-10aa-4055-94e6-47200d691335","order":12,"chinese":"任何人都会有兴趣看书","pinyin":"rèn hé rén dōu huì yǒu xìng qù kàn shū","english":"Anyone would be interested in reading","audioUrl":null},{"id":"765faa31-b8c4-4b61-a46b-aa2bb9ff3c91","order":13,"chinese":"我也觉得这个很难选","pinyin":"wǒ yě jué de zhè ge hěn nán xuǎn","english":"I also think this is hard to choose","audioUrl":null}]}'::jsonb),
  (7, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"da909db1-d6fa-43a4-8019-4688d4080b9f","order":0,"chinese":"我们在银行已经过了三个小时","pinyin":"wǒ men zài yín háng yǐ jīng guò le sān gè xiǎo shí","english":"We''ve already spent three hours at the bank","audioUrl":null},{"id":"ef669ae5-0cc3-4d6c-a2fd-49c369a1669f","order":1,"chinese":"二十五个小时之后, 你终于到了","pinyin":"èr shí wǔ gè xiǎo shí zhī hòu nǐ zhōng yú dào le","english":"After twenty-five hours, you finally arrived","audioUrl":null},{"id":"042ca438-ea04-4aec-825a-4f4703369579","order":2,"chinese":"六个小时之后, 你要记得煮饭","pinyin":"liù gè xiǎo shí zhī hòu nǐ yào jì de zhǔ fàn","english":"Six hours from now, remember to cook","audioUrl":null},{"id":"59575266-9551-44f9-a5a1-e8ee4ab291b7","order":3,"chinese":"这个礼物是她刚刚送给我的","pinyin":"zhè ge lǐ wù shì tā gāng gang sòng gěi wǒ de","english":"She just gave me this gift","audioUrl":null},{"id":"3f65f528-aca6-4c3f-97b6-dc9b1293b4c5","order":4,"chinese":"我真的不喜欢喝咖啡","pinyin":"wǒ zhēn de bù xǐ huan hē kā fēi","english":"I really don''t like drinking coffee","audioUrl":null},{"id":"2776a90f-758d-4274-8288-4cfc531b18a8","order":5,"chinese":"吃饭之前要先去洗手间洗手","pinyin":"chī fàn zhī qián yào xiān qù xǐ shǒu jiān xǐ shǒu","english":"Before eating, go to the bathroom and wash your hands first","audioUrl":null},{"id":"9636773d-df76-4df3-af38-5983fd1c8b2e","order":6,"chinese":"请你先考完试再说","pinyin":"qǐng nǐ xiān kǎo wán shì zài shuō","english":"Finish your exam first, then we''ll talk","audioUrl":null},{"id":"10071be6-1a1d-462e-b6d6-2e803f1dcdce","order":7,"chinese":"我喜欢先读完书再睡觉","pinyin":"wǒ xǐ huān xiān dú wán shū zài shuì jiào","english":"I like to finish reading before going to sleep","audioUrl":null},{"id":"1ba5d7e1-e675-48b0-9c40-2dd79ebf12af","order":8,"chinese":"你要在地铁站等一会","pinyin":"nǐ yào zài dì tiě zhàn děng yí huì","english":"You''ll have to wait a while at the subway station","audioUrl":null},{"id":"0d497580-eb67-4f00-b5c7-7002d2570b29","order":9,"chinese":"我很忙! 你可以等一会吗？","pinyin":"wǒ hěn máng nǐ kě yǐ děng yí huì ma","english":"I''m very busy! Can you wait a moment?","audioUrl":null},{"id":"46608f2a-619f-442f-a7af-87865ca62021","order":10,"chinese":"累死我了. 我要休息一会","pinyin":"lèi sǐ wǒ le wǒ yào xiū xi yí huì","english":"I''m exhausted. I need to rest for a bit","audioUrl":null},{"id":"edd9a558-21e8-47b4-bf8a-d1b63d6c0542","order":11,"chinese":"我今天真的超级累","pinyin":"wǒ jīn tiān zhēn de chāo jí lèi","english":"I''m really super tired today","audioUrl":null},{"id":"4c6909f5-2c10-4e37-b654-0529f60e9bdc","order":12,"chinese":"你现在很累吗","pinyin":"nǐ xiàn zài hěn lèi ma","english":"Are you very tired right now?","audioUrl":null},{"id":"ca9cec8a-614e-4e4b-985d-278088410580","order":13,"chinese":"当船进来的时候, 我会放心","pinyin":"dāng chuán jìn lái de shí hòu wǒ huì fàng xīn","english":"When the boat comes in, I''ll feel relieved","audioUrl":null},{"id":"87531482-24bd-455b-9c21-4a7109c1ded5","order":14,"chinese":"为什么当我需要帮助的时候, 你们都不在？","pinyin":"wèi shén me dāng wǒ xū yào bāng zhù de shí hòu nǐ men dōu bú zài","english":"Why is it that when I need help, none of you are around?","audioUrl":null},{"id":"82eae5ad-fbd9-4c6c-ae63-459ae1fb07cb","order":15,"chinese":"医生已经等了几个小时...","pinyin":"yī shēng yǐ jīng děng le jǐ ge xiǎo shí","english":"The doctor has already been waiting for hours...","audioUrl":null},{"id":"d6f1d4e0-ceb1-4cf1-8fdd-a346f62a5f0f","order":16,"chinese":"我刚刚上了出租车! 一会就到了","pinyin":"wǒ gāng gang shàng le chū zū chē yí huì jiù dào le","english":"I just got in a taxi! I''ll be there in a bit","audioUrl":null},{"id":"7094a813-b851-4fa0-bcbb-3a120eb3e075","order":17,"chinese":"外面很冷, 你可以先关门吗","pinyin":"wài miàn hěn lěng nǐ kě yǐ xiān guān mén ma","english":"It''s cold outside — can you close the door first?","audioUrl":null},{"id":"fabfd0e6-da1f-40c9-8eb2-75702b4fa6b6","order":18,"chinese":"外面很冷, 你可不可以先关门","pinyin":"wài miàn hěn lěng nǐ kě bù kě yǐ xiān guān mén","english":"It''s cold outside — could you close the door first?","audioUrl":null}]}'::jsonb),
  (8, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"5c690881-7b5c-45bc-99dd-a5a266a5b3c2","order":0,"chinese":"不用等我! 你先上公共汽车吧","pinyin":"bú yòng děng wǒ nǐ xiān shàng gōng gòng qì chē ba","english":"Don''t wait for me! Go ahead and get on the bus","audioUrl":null},{"id":"6173be76-bfd7-4c91-b025-2506d8d245ab","order":1,"chinese":"你一点汤都不要吗? 喝一点吧","pinyin":"nǐ yì diǎn tāng dōu bú yào ma hē yì diǎn ba","english":"You don''t want any soup at all? Have a little","audioUrl":null},{"id":"39c92e26-12df-432b-8cd9-0e996d3e6685","order":2,"chinese":"北方很热! 你快点回来吧!","pinyin":"běi fāng hěn rè nǐ kuài diǎn huí lái ba","english":"The north is really hot! Hurry back!","audioUrl":null},{"id":"6d457792-7dba-43df-bc50-fed0a1e050ef","order":3,"chinese":"其他医院会有更多病人吧","pinyin":"qí tā yī yuàn huì yǒu gèng duō bìng rén ba","english":"Other hospitals probably have more patients","audioUrl":null},{"id":"af3be05f-a4b7-454d-ae6c-9dba98b5e172","order":4,"chinese":"这个办法更好","pinyin":"zhè ge bàn fǎ gèng hǎo","english":"This method is better","audioUrl":null},{"id":"cd8cae32-6e8d-474c-9413-c262531e5dd4","order":5,"chinese":"请你给我一杯冰水吧","pinyin":"qǐng nǐ gěi wǒ yì bēi bīng shuǐ ba","english":"Please give me a glass of ice water","audioUrl":null},{"id":"21ea5b02-b00a-4ee3-9c84-bc751d3d57c5","order":6,"chinese":"穿衣服吧! 我们一起出去吧","pinyin":"chuān yī fu ba wǒ men yì qǐ chū qù ba","english":"Get dressed! Let''s go out together","audioUrl":null},{"id":"f7b0fc27-c149-491e-8c1e-c972d78c301f","order":7,"chinese":"我们一起聊天吧","pinyin":"wǒ men yì qǐ liáo tiān ba","english":"Let''s chat together","audioUrl":null},{"id":"da6383c1-bd05-4a2b-9d55-a42a6d332e10","order":8,"chinese":"你们都很饿, 对吧?","pinyin":"nǐ men dōu hěn è duì ba","english":"You''re all hungry, right?","audioUrl":null},{"id":"eda56e01-741c-4fec-afe5-2f5af7d0a95e","order":9,"chinese":"你们都很饿吧?","pinyin":"nǐ men dōu hěn è ba","english":"You''re all hungry, aren''t you?","audioUrl":null},{"id":"ddacfe8e-9cc9-4bce-a0cf-11ef6eae4241","order":10,"chinese":"他姓何, 对吧?","pinyin":"tā xìng hé duì ba","english":"His surname is He, right?","audioUrl":null},{"id":"555351b5-42f8-436d-bdef-2f0bcf6e71aa","order":11,"chinese":"我昨天得到四十三分! 不错吧?","pinyin":"wǒ zuó tiān dé dào sì shí sān fēn bú cuò ba","english":"I got forty-three points yesterday! Not bad, right?","audioUrl":null},{"id":"87653f2c-db50-48e9-aa72-3175552e089f","order":12,"chinese":"选这个颜色吧! 这个更好看","pinyin":"xuǎn zhè ge yán sè ba zhè ge gèng hǎo kàn","english":"Go with this color! This one looks better","audioUrl":null},{"id":"271eb7b2-35ca-4d5a-9093-9d2696487d82","order":13,"chinese":"汤还是很热! 喝慢一点吧!","pinyin":"tāng hái shi hěn rè hē màn yì diǎn ba","english":"The soup is still hot! Drink it slowly!","audioUrl":null},{"id":"87638a86-971a-41d7-a0ea-09e62809ac6c","order":14,"chinese":"其他地方都没有这里那么有名吧!","pinyin":"qí tā dì fāng dōu méi yǒu zhè lǐ nà me yǒu míng ba","english":"No other place is as famous as here, right?","audioUrl":null}]}'::jsonb),
  (9, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"8d2d11f3-cb12-470e-88ca-4a20d443b0a5","order":0,"chinese":"我觉得他比你更帅","pinyin":"wǒ jué de tā bǐ nǐ gèng shuài","english":"I think he''s more handsome than you","audioUrl":null},{"id":"b16d6c48-39e5-4790-b75e-8933211e1356","order":1,"chinese":"哇! 你开车的时候太帅了","pinyin":"wā nǐ kāi chē de shí hòu tài shuài le","english":"Wow! You look so cool when you drive","audioUrl":null},{"id":"b3b71ed6-0203-487a-bd63-1dc4452b97a5","order":2,"chinese":"我发现坐地铁去上班比较方便","pinyin":"wǒ fā xiàn zuò dì tiě qù shàng bān bǐ jiào fāng biàn","english":"I''ve found that taking the subway to work is more convenient","audioUrl":null},{"id":"915e74c2-57e6-4bdd-99df-2f0f64b19a30","order":3,"chinese":"我发现这些问题都比较简单","pinyin":"wǒ fā xiàn zhè xiē wèn tí dōu bǐ jiào jiǎn dān","english":"I''ve found that these questions are relatively easy","audioUrl":null},{"id":"6b52289a-b11c-4007-84e5-f9f6f8f25772","order":4,"chinese":"我发现这个女人比较漂亮一点","pinyin":"wǒ fā xiàn zhè ge nǚ ren bǐ jiào piào liang yì diǎn","english":"I''ve found this woman is a bit prettier","audioUrl":null},{"id":"958d8f52-ddfd-4d33-81c9-438833d797ae","order":5,"chinese":"这幅画很漂亮, 多少钱?","pinyin":"zhè fú huà hěn piào liang duō shao qián","english":"This painting is beautiful — how much is it?","audioUrl":null},{"id":"f20ff5d2-5d2a-4428-aca9-3fe8ed277864","order":6,"chinese":"我比较想知道为什么你还没结婚","pinyin":"wǒ bǐ jiào xiǎng zhī dào wèi shén me nǐ hái méi jié hūn","english":"I''d rather know why you''re still not married","audioUrl":null},{"id":"554fe8f8-ea81-42fc-816f-e3bd4471f266","order":7,"chinese":"比起以前, 中国的熊猫现在没有那么胖","pinyin":"bǐ qǐ yǐ qián zhōng guó de xióng māo xiàn zài méi yǒu nà me pàng","english":"Compared to before, China''s pandas aren''t as fat now","audioUrl":null},{"id":"2d33fb4c-5ec3-45ab-aae5-76e77376f076","order":8,"chinese":"比起现在, 我觉得以前的菜比较新鲜","pinyin":"bǐ qǐ xiàn zài wǒ jué de yǐ qián de cài bǐ jiào xīn xiān","english":"Compared to now, I think the food before was fresher","audioUrl":null},{"id":"a3140a83-60f5-4ad7-9a26-e2294e40bd59","order":9,"chinese":"比起以前, 我现在更害怕全球环境变化","pinyin":"bǐ qǐ yǐ qián wǒ xiàn zài gèng hài pà quán qiú huán jìng biàn huà","english":"Compared to before, I''m now more afraid of global environmental change","audioUrl":null},{"id":"ef199565-ce72-4418-b25a-d90df18a0685","order":10,"chinese":"奶奶比你漂亮但是你比她年轻","pinyin":"nǎi nai bǐ nǐ piào liang dàn shì nǐ bǐ tā nián qīng","english":"Grandma is prettier than you, but you''re younger than her","audioUrl":null},{"id":"edd304c3-3b42-44a4-9ce9-438d3349035e","order":11,"chinese":"写汉语在黑板上比较清楚","pinyin":"xiě hàn yǔ zài hēi bǎn shàng bǐ jiào qīng chǔ","english":"Writing Chinese on the blackboard is clearer","audioUrl":null},{"id":"44bf636e-a834-453e-a497-7e6f2dd806b0","order":12,"chinese":"坐地铁上班应该比较方便吧","pinyin":"zuò dì tiě shàng bān yīng gāi bǐ jiào fāng biàn ba","english":"Taking the subway to work should be more convenient, right?","audioUrl":null}]}'::jsonb),
  (10, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"91291bf7-9477-4233-a62b-2bf2f6b0601f","order":0,"chinese":"我的铅笔又被人偷了","pinyin":"wǒ de qiān bǐ yòu bèi rén tōu le","english":"My pencil got stolen again","audioUrl":null},{"id":"6b1bab3d-3c85-432e-a77c-ad96d6b8799a","order":1,"chinese":"垃圾被我扔了","pinyin":"lā jī bèi wǒ rēng le","english":"The trash was thrown out by me","audioUrl":null},{"id":"0c290f98-15a8-4f63-ae4e-836c4529c0ec","order":2,"chinese":"我不想给他们发现","pinyin":"wǒ bù xiǎng gěi tā men fā xiàn","english":"I don''t want to be discovered by them","audioUrl":null},{"id":"5c489da3-9a3a-46d3-b88f-484b174c796c","order":3,"chinese":"那枝筷子已经给服务员拿走了","pinyin":"nà zhī kuài zi yǐ jīng gěi fú wù yuán ná zǒu le","english":"That chopstick has already been taken away by the waiter","audioUrl":null},{"id":"0aeb0978-779a-4f25-91ca-c6b4c2d4eb3c","order":4,"chinese":"那么好的机会被你浪费了","pinyin":"nà me hǎo de jī huì bèi nǐ làng fèi le","english":"Such a good opportunity was wasted by you","audioUrl":null},{"id":"c751d6bb-f670-4a4a-8b58-7693d00656c6","order":5,"chinese":"不要浪费钱","pinyin":"bú yào làng fèi qián","english":"Don''t waste money","audioUrl":null},{"id":"763a546d-21be-457b-9c29-0561266b4e52","order":6,"chinese":"我今天浪费了很多时间","pinyin":"wǒ jīn tiān làng fèi le hěn duō shí jiān","english":"I wasted a lot of time today","audioUrl":null},{"id":"5c7d49ef-85a5-471f-ba73-c206527ae500","order":7,"chinese":"快点吃饭! 不要浪费","pinyin":"kuài diǎn chī fàn bú yào làng fèi","english":"Hurry up and eat! Don''t waste it","audioUrl":null},{"id":"0aeb68a3-32ad-4e23-971a-963f420cd5fe","order":8,"chinese":"所有钱都被你浪费了","pinyin":"suǒ yǒu qián dōu bèi nǐ làng fèi le","english":"All the money was wasted by you","audioUrl":null},{"id":"f2f8b4ad-f2e9-44ac-92b6-ad9683565d89","order":9,"chinese":"如果你不准备好, 机会会被你浪费","pinyin":"rú guǒ nǐ bù zhǔn bèi hǎo jī huì huì bèi nǐ làng fèi","english":"If you don''t get ready, the opportunity will be wasted by you","audioUrl":null},{"id":"d445c680-9439-4f80-91ad-f11780b66b15","order":10,"chinese":"全部垃圾都被我扔了","pinyin":"quán bù lā jī dōu bèi wǒ rēng le","english":"All the trash was thrown out by me","audioUrl":null}]}'::jsonb),
  (11, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"8e97bd75-5e23-49ab-9b3b-ea48f78b4bfc","order":0,"chinese":"我今晚可能不回来","pinyin":"wǒ jīn wǎn kě néng bù huí lai","english":"I might not come back tonight","audioUrl":null},{"id":"bcbb346e-00af-4638-8411-8f578199cf3c","order":1,"chinese":"如果我们小声一点, 我们可能不会被他发现","pinyin":"rú guǒ wǒ men xiǎo shēng yì diǎn wǒ men kě néng bú huì bèi tā fā xiàn","english":"If we''re a bit quieter, we might not get noticed by him","audioUrl":null},{"id":"8b59675c-8f52-4f84-bd2d-17b60c7a6535","order":2,"chinese":"我突然要上厕所","pinyin":"wǒ tū rán yào shàng cè suǒ","english":"I suddenly need to use the toilet","audioUrl":null},{"id":"0c0faef1-94a8-4028-bfc8-a55bd2d2d595","order":3,"chinese":"你要上厕所吗","pinyin":"nǐ yào shàng cè suǒ ma","english":"Do you need to use the toilet?","audioUrl":null},{"id":"45f62ed6-798e-4e81-a555-c6a7f6b6ad85","order":4,"chinese":"我本来是想照顾你的, 不过我现在不想了","pinyin":"wǒ běn lái shì xiǎng zhào gù nǐ de bú guò wǒ xiàn zài bù xiǎng le","english":"I originally wanted to take care of you, but now I don''t want to anymore","audioUrl":null},{"id":"a26a390a-efac-4950-b02c-5425ee2bd7ec","order":5,"chinese":"我最近没有看新闻","pinyin":"wǒ zuì jìn méi yǒu kàn xīn wén","english":"I haven''t been watching the news lately","audioUrl":null},{"id":"10e9ebb5-048a-4af9-aa1c-424af34f7e45","order":6,"chinese":"好像我们最近都没有去运动","pinyin":"hǎo xiàng wǒ men zuì jìn dōu méi yǒu qù yùn dòng","english":"It seems we haven''t gone to exercise lately","audioUrl":null},{"id":"fc9c087d-6558-4050-b2ce-e47e069de4a6","order":7,"chinese":"我很想知道你的眼睛曾经见过什么","pinyin":"wǒ hěn xiǎng zhī dào nǐ de yǎn jing céng jīng jiàn guo shén me","english":"I really want to know what your eyes have seen before","audioUrl":null},{"id":"3ef4260c-cbf5-4b28-959d-c292bc73dbaf","order":8,"chinese":"几乎每个人的行李都要被检查","pinyin":"jī hū měi ge rén de xíng li dōu yào bèi jiǎn chá","english":"Almost everyone''s luggage has to be checked","audioUrl":null},{"id":"8652cc55-2ac4-4bdc-a592-1561eb5932d3","order":9,"chinese":"我几乎笑到肚子痛","pinyin":"wǒ jī hū xiào dào dù zi tòng","english":"I almost laughed until my stomach hurt","audioUrl":null},{"id":"4fadee43-fa02-4e3b-a92f-0c1f0c1a16e5","order":10,"chinese":"他一个人几乎吃了整个蛋糕, 应该吃饱了吧","pinyin":"tā yí gè rén jī hū chī le zhěng ge dàn gāo yīng gāi chī bǎo le ba","english":"He almost ate the whole cake by himself — he must be full, right?","audioUrl":null},{"id":"89e48fed-f6a1-4b5e-92c3-6456b594721a","order":11,"chinese":"整个国际社会都同意","pinyin":"zhěng gè guó jì shè huì dōu tóng yì","english":"The entire international community agrees","audioUrl":null},{"id":"068bcad2-3119-43a6-af7f-f0430d264141","order":12,"chinese":"我本来不相信你, 但是现在我信了","pinyin":"wǒ běn lái bù xiāng xìn nǐ dàn shì xiàn zài wǒ xìn le","english":"I didn''t believe you at first, but now I do","audioUrl":null},{"id":"3acc61b0-d842-4933-ad22-f3026ab0945a","order":13,"chinese":"跳这么高是不可能的","pinyin":"tiào zhè me gāo shì bù kě néng de","english":"Jumping this high is impossible","audioUrl":null},{"id":"b3427c44-e49d-41cf-8b42-6e41fbc76a34","order":14,"chinese":"你为什么要突然出来? 我还没化妆","pinyin":"nǐ wèi shén me yào tū rán chū lái wǒ hái méi huà zhuāng","english":"Why did you come out all of a sudden? I haven''t put on makeup yet","audioUrl":null}]}'::jsonb),
  (12, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"2eed01b0-c57d-45a1-95f7-37f81d9b7913","order":0,"chinese":"然后我们要去买最便宜的饮料","pinyin":"rán hòu wǒ men yào qù mǎi zuì pián yí de yǐn liào","english":"Then we''re going to buy the cheapest drinks","audioUrl":null},{"id":"e1eb193f-2da8-4aff-b6bd-f8fb7df3de31","order":1,"chinese":"先打开冰箱, 然后帮我拿一些吃的","pinyin":"xiān dǎ kāi bīng xiāng rán hòu bāng wǒ ná yī xiē chī de","english":"Open the fridge first, then get me some food","audioUrl":null},{"id":"2a9dde08-6a48-469c-950a-58ef707e2a4b","order":2,"chinese":"然后医生和我说, 生病了一定要吃药","pinyin":"rán hòu yī shēng hé wǒ shuō shēng bìng le yí dìng yào chī yào","english":"Then the doctor told me: when you''re sick, you must take medicine","audioUrl":null},{"id":"df9e7884-b038-4980-854d-5a104a90851c","order":3,"chinese":"马上上去楼上, 然后帮我拿我的眼镜","pinyin":"mǎ shàng shàng qù lóu shàng rán hòu bāng wǒ ná wǒ de yǎn jīng","english":"Go upstairs right now, then get me my glasses","audioUrl":null},{"id":"614e18a6-f1d6-49a5-b5fc-17dacce473de","order":4,"chinese":"你们原来住在东边, 但是最近搬到西边","pinyin":"nǐ men yuán lái zhù zài dōng bian dàn shì zuì jìn bān dào xī bian","english":"You used to live on the east side, but recently moved to the west side","audioUrl":null},{"id":"8e271fcc-df89-4921-9675-d0cb95dc4e97","order":5,"chinese":"原来他没有发烧他只是感冒","pinyin":"yuán lái tā méi yǒu fā shāo tā zhǐ shì gǎn mào","english":"It turns out he didn''t have a fever, he just had a cold","audioUrl":null},{"id":"ea50b046-83e0-49b6-b924-664e3e060aad","order":6,"chinese":"我猜两个答案应该都一样","pinyin":"wǒ cāi liǎng gè dá àn yīng gāi dōu yí yàng","english":"I''m guessing both answers should be the same","audioUrl":null},{"id":"e90bf06c-67b0-4574-a59a-be1b9bb3789c","order":7,"chinese":"反正我肚子饿, 你弄点吃的吧","pinyin":"fǎn zhèng wǒ dù zi è nǐ nòng diǎn chī de ba","english":"I''m hungry anyway, so make something to eat","audioUrl":null},{"id":"c3e9f1b3-bc49-4147-9064-64cb9d0cb044","order":8,"chinese":"没关系, 反正我现在不想要了, 真的","pinyin":"méi guān xì fǎn zhèng wǒ xiàn zài bù xiǎng yào le zhēn de","english":"It''s okay, I don''t want it anymore anyway, really","audioUrl":null},{"id":"f825ff3e-52fd-42d7-b342-fe5a9abf202b","order":9,"chinese":"先猜我有多少钱, 然后选餐厅","pinyin":"xiān cāi wǒ yǒu duō shǎo qián rán hòu xuǎn cān tīng","english":"First guess how much money I have, then pick a restaurant","audioUrl":null},{"id":"452e6a59-c214-4858-821f-48dc66091fd0","order":10,"chinese":"马上拿一张信用卡出来! 然后买这条裤子!","pinyin":"mǎ shàng ná yī zhāng xìn yòng kǎ chū lái rán hòu mǎi zhè tiáo kù zi","english":"Take out a credit card right now! Then buy these pants!","audioUrl":null},{"id":"7967566e-1319-4f53-b99b-e2d7e152f36f","order":11,"chinese":"原来是你偷了老爷的钱","pinyin":"yuán lái shì nǐ tōu le lǎo yé de qián","english":"So it was you who stole the master''s money","audioUrl":null}]}'::jsonb),
  (13, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"1f71f936-27c8-49d0-83b4-0fc7164164b0","order":0,"chinese":"你最近怎么样?","pinyin":"nǐ zuì jìn zěn me yàng","english":"How have you been lately?","audioUrl":null},{"id":"7966bea2-ef05-4d9c-a26c-df4148681c44","order":1,"chinese":"儿子过来教爸爸怎么用电脑","pinyin":"ér zi guò lai jiāo bà ba zěn me yòng diàn nǎo","english":"The son comes over to teach his dad how to use the computer","audioUrl":null},{"id":"1ca98ae8-0bb2-4e4f-9c68-ddd7a874d4ac","order":2,"chinese":"我特别喜欢中国文化, 你呢?","pinyin":"wǒ tè bié xǐ huan zhōng guó wén huà nǐ ne","english":"I especially love Chinese culture — how about you?","audioUrl":null},{"id":"cec60079-4bb9-416d-aab5-906cb54884ad","order":3,"chinese":"这个用中文怎么说? 那个呢?","pinyin":"zhè ge yòng zhōng wén zěn me shuō nà ge ne","english":"How do you say this in Chinese? And that one?","audioUrl":null},{"id":"be9d69d5-93ab-4d61-b345-1cfcaa042995","order":4,"chinese":"我已经改变了我的答案. 你呢?","pinyin":"wǒ yǐ jīng gǎi biàn le wǒ de dá àn nǐ ne","english":"I''ve already changed my answer. How about you?","audioUrl":null},{"id":"5103ec0c-6534-4589-b449-ac6fd88b2811","order":5,"chinese":"爸爸那时候十九岁就已经找到妻子了","pinyin":"bà ba nà shí hou shí jiǔ suì jiù yǐ jīng zhǎo dào qī zi le","english":"Back then, at nineteen, Dad had already found a wife","audioUrl":null},{"id":"093640e7-4f31-4e28-9909-a50e67fcfa38","order":6,"chinese":"你什么时候有空? 我想和你一起听音乐","pinyin":"nǐ shén me shí hou yǒu kòng wǒ xiǎng hé nǐ yì qǐ tīng yīn yuè","english":"When are you free? I want to listen to music with you","audioUrl":null},{"id":"067d4b22-e6cf-47a7-be7b-0f4d7345a5e9","order":7,"chinese":"你到底想不想解决这个问题","pinyin":"nǐ dào dǐ xiǎng bù xiǎng jiě jué zhè ge wèn tí","english":"Do you actually want to solve this problem or not?","audioUrl":null},{"id":"5831e07d-63ee-4f40-87ec-99f17381cb84","order":8,"chinese":"你不可能知道到底正在发生什么事情","pinyin":"nǐ bù kě néng zhī dào dào dǐ zhèng zài fā shēng shén me shì qíng","english":"There''s no way you could know what''s actually happening","audioUrl":null},{"id":"34599d05-2288-4bce-a618-832985168afc","order":9,"chinese":"我在唱歌","pinyin":"wǒ zài chàng gē","english":"I''m singing","audioUrl":null},{"id":"6d31445f-833b-4c89-8701-77ad4e2a578f","order":10,"chinese":"我正在唱歌","pinyin":"wǒ zhèng zài chàng gē","english":"I''m singing right now","audioUrl":null},{"id":"09589b19-f761-4137-8dac-a6301b5e7af2","order":11,"chinese":"你觉得他写的怎么样?","pinyin":"nǐ jué de tā xiě de zěn me yàng","english":"What do you think of what he wrote?","audioUrl":null},{"id":"ce462318-b2a6-486e-9c5a-67c78baa2a25","order":12,"chinese":"我很喜欢这两位歌手! 你呢?","pinyin":"wǒ hěn xǐ huan zhè liǎng wèi gē shǒu nǐ ne","english":"I really like these two singers! How about you?","audioUrl":null},{"id":"f39345e6-4faf-4367-af7a-5feabd17385c","order":13,"chinese":"明天怎么样? 有没有空?","pinyin":"míng tiān zěn me yàng yǒu méi yǒu kòng","english":"How about tomorrow? Are you free?","audioUrl":null},{"id":"21a919b2-5f70-4690-91c1-10260782992d","order":14,"chinese":"明天怎么样? 有空吗?","pinyin":"míng tiān zěn me yàng yǒu kòng ma","english":"How about tomorrow? Are you free?","audioUrl":null}]}'::jsonb)
) AS v(n, content)
WHERE l."lesson_type" = 'audio'
  AND l."deleted_at" IS NULL
  AND l."title" ILIKE '%intensive listening%'
  AND (substring(lower(l."title") from 'intermediate[^0-9]*([0-9]+)'))::int = v.n
  AND l."module_id" IN (
    SELECT m."id"
    FROM "course_library_modules" m
    JOIN "course_library_courses" c ON c."id" = m."course_id"
    WHERE m."deleted_at" IS NULL
      AND c."deleted_at" IS NULL
      AND lower(trim(c."title")) = 'the canto to mando blueprint - intermediate'
  );
